    "cases.design_query_from_bim_coordination.step.query.in.viewpoint": "Vista do modelo",
    "cases.design_query_from_bim_coordination.step.query.out.rfi": "Consulta de projeto formal",
    "cases.design_query_from_bim_coordination.step.query.out.tracked": "RFI rastreado",
    "cases.design_query_from_bim_coordination.step.query.title": "Levantar a consulta",
    "cases.design_query_from_bim_coordination.step.query.what": "Levante um pedido formal identificando o elemento, a vista do modelo em que foi encontrado e a colisão ou conflito que provoca, com uma data ligada ao momento em que o ofício precisa da resposta.",
    "cases.design_query_from_bim_coordination.step.query.why": "Um conflito referido numa reunião e nunca formalizado é esquecido na reunião seguinte. Uma consulta datada e escrita é o que a mantém em curso até ser efetivamente resolvida.",
    "cases.design_query_from_bim_coordination.step.review.in.federation": "Modelo federado",
