    "cases.design_query_from_bim_coordination.step.review.out.conflict": "Conflito localizado",
    "cases.design_query_from_bim_coordination.step.review.out.discipline": "Disciplina responsável",
    "cases.design_query_from_bim_coordination.step.review.title": "Rever o modelo federado",
    "cases.design_query_from_bim_coordination.step.review.what": "Abra a federação e reveja a área sinalizada na reunião de coordenação, verificando qual o modelo da disciplina que efetivamente precisa de ser alterado.",
    "cases.design_query_from_bim_coordination.step.review.why": "Uma consulta levantada contra a disciplina errada volta simplesmente uma semana depois. Confirmar a origem primeiro na vista federada é o que a leva à secretária certa logo à primeira.",
    "cases.design_query_from_bim_coordination.step.update.in.answer": "Resposta à consulta",
    "cases.design_query_from_bim_coordination.step.update.in.conflict": "Conflito original",
    "cases.design_query_from_bim_coordination.step.update.in.model": "Modelo afetado",
    "cases.design_query_from_bim_coordination.step.update.out.updated": "Modelo atualizado",
    "cases.design_query_from_bim_coordination.step.update.out.verified": "Correção verificada",
    "cases.design_query_from_bim_coordination.step.update.title": "Atualizar o modelo",
    "cases.design_query_from_bim_coordination.step.update.what": "Assim que a resposta chegar, atualize o modelo afetado e confirme a correção face ao conflito original antes de ser reemitido à equipa.",
    "cases.design_query_from_bim_coordination.step.update.why": "A consulta só fecha o ciclo quando o próprio modelo reflete a correção. Caso contrário, o mesmo conflito volta a surgir da próxima vez que alguém federar o conjunto.",
    "cases.design_query_from_bim_coordination.title": "Levantar uma consulta de projeto a partir da coordenação BIM",
    "cases.draft_an_estimate_with_ai_element_matching.desc": "Associe elementos importados a itens de custo, deixe a IA orçamentar o âmbito, aceite-o no mapa de quantidades e valide antes de confiar nele.",
    "cases.draft_an_estimate_with_ai_element_matching.step.accept-boq.in.lines": "Linhas orçamentadas confirmadas",
