    "cases.draft_an_estimate_with_ai_element_matching.step.match.out.scores": "Pontuações de confiança",
    "cases.draft_an_estimate_with_ai_element_matching.step.match.title": "Associar elementos a itens de custo",
    "cases.draft_an_estimate_with_ai_element_matching.step.match.what": "Importe os seus elementos e descrições e deixe o associador ligar cada um a um item da base de dados de custos, com uma pontuação de confiança em cada associação.",
    "cases.draft_an_estimate_with_ai_element_matching.step.match.why": "Codificar centenas de linhas manualmente é lento e desigual. As associações pontuadas mostram onde confiar na máquina e onde verificar manualmente.",
    "cases.draft_an_estimate_with_ai_element_matching.step.validate.in.boq": "Mapa de quantidades preliminar",
