    "cases.run_the_submittals_register.step.issue-review.title": "Enviar para revisão",
    "cases.run_the_submittals_register.step.issue-review.what": "Na Correspondência, envie a submissão para revisão e registe o estado devolvido: aprovado, aprovado com comentários ou rejeitado.",
    "cases.run_the_submittals_register.step.issue-review.why": "O estado devolvido é o gatilho para encomendar ou para ressubmeter, por isso tem de ficar registado contra o item. Um sim verbal não liberta o aprovisionamento.",
    "cases.run_the_submittals_register.step.log.in.drawings": "Desenhos de execução",
