    "cases.run_the_submittals_register.step.log.title": "Registar as submissões",
    "cases.run_the_submittals_register.step.log.what": "Nas Submissões, registe cada desenho de execução e submissão técnica e defina a data até à qual a aprovação é necessária.",
    "cases.run_the_submittals_register.step.log.why": "Uma submissão aprovada com atraso atrasa a encomenda, e uma encomenda atrasada atrasa o subempreiteiro na obra. O registo é onde vê isso a aproximar-se.",
    "cases.run_the_submittals_register.step.report.in.log": "Registo de submissões",
    "cases.run_the_submittals_register.step.report.in.statuses": "Estados de revisão",
