    "demo_banner.modal_title": "Esta é uma demo pública",
    "demo_banner.modal_subtitle": "Leia isto antes de explorar",
    "demo_banner.modal_sample_data_label": "Dados de exemplo",
    "demo_banner.modal_sample_data_body": "Todos os projetos, BOQs e valores aqui apresentados são dados de exemplo criados apenas para fins de demonstração. Nada aqui são dados reais de projeto.",
    "demo_banner.modal_intro_before_vps": "Está a ver a demo pública alojada do",
    "demo_banner.modal_intro_runs_on": "É executada num",
    "demo_banner.modal_intro_vps_spec": "pequeno VPS de ~2 GB RAM",
    "demo_banner.modal_intro_shared": "partilhado com todos os visitantes na internet - destina-se a uma",
    "demo_banner.modal_intro_walkthrough": "visita rápida e superficial",
    "demo_banner.modal_intro_nothing_more": "do produto, nada mais. Especificamente:",
    "demo_banner.modal_bullet_no_data_heading": "Não carregue dados reais ou confidenciais.",
    "demo_banner.modal_bullet_no_data_body": "Tudo o que colocar aqui fica visível para outros visitantes da demo.",
    "demo_banner.modal_bullet_perf_heading": "Espere um desempenho mais lento do que numa instalação local.",
    "demo_banner.modal_bullet_perf_body": "Este é um servidor partilhado de 1-core. As funcionalidades pesadas (conversão CAD/BIM, inferência de AI, pesquisa vetorial) precisam de RAM real e estão otimizadas para instalações locais - na máquina de demo de ~2 GB podem estar lentas, limitadas por taxa ou simplesmente indisponíveis. Para benchmarks ou fluxos de trabalho completos, instale localmente.",
    "demo_banner.modal_bullet_install_heading": "Instale localmente para trabalho real.",
    "demo_banner.modal_bullet_install_body": "O produto completo é executado na sua própria máquina em dois minutos. Os seus dados permanecem no seu computador.",
    "demo_banner.modal_install_box_label": "Instalar localmente - 3 comandos",
    "demo_banner.modal_cta": "Compreendo, continuar",
    "sidebar.video_news.title": "Uberização da Construção",
    "costs.category_field_hint": "Agrupe este item, por exemplo \"Estrutura Metálica\". Consulte-o depois na lista de Categorias.",
    "costs.category_field_label": "Categoria",
    "costs.category_field_placeholder": "por exemplo, Estrutura Metálica",
    "costs.mass_basis_kg": "por kg",
    "costs.mass_basis_label": "O preço é",
