    "dashboards.snapshots_subtitle": "Congele um conjunto de dados parquet dos seus arquivos CAD/BIM e depois compare os instantâneos ao longo do tempo.",
    "dashboards.view_list": "Capturas",
    "dashboards.view_timeline": "Linha do tempo",
